/**
 * Common primitive utility functions shared across core modules.
 *
 * These reduce duplication of trivial helpers like string-presence checks,
 * error message extraction, and numeric array guards that were previously
 * duplicated in providers.ts, vector-stores.ts, lock.ts, cache.ts, and
 * several CLI command modules.
 */
export declare function toNonEmptyString(value: unknown): string | null;
export declare function toNonEmptyStringOrUndefined(value: unknown): string | undefined;
export declare function trimTrailingSlashes(value: string): string;
export declare function isFiniteNumberArray(value: unknown): value is number[];
export declare function toErrorMessage(error: unknown): string;
